import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { UserSession } from '../../src/entities/user-session.entity';
import { buildUserSession } from '../factories/user-session.factory';
import { User } from '../../src/entities/user.entity';
import { buildUser } from '../factories/user.factory';

describe('UserSession Repository', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<UserSession>;
  let userId: string;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(UserSession);
  });

  beforeEach(async () => {
    const userEntity = await dataSource
      .getRepository(User)
      .save(
        dataSource.getRepository(User).create(
          buildUser(),
        ),
      );
    userId = userEntity.id;
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  it('creates and persists an entity', async () => {
    const data = buildUserSession({ userId: userId });
    const entity = repository.create(data);
    const saved = await repository.save(entity);
    expect(saved.id).toBeDefined();
  });

  it('retrieves an entity by id', async () => {
    const data = buildUserSession({ userId: userId });
    const saved = await repository.save(repository.create(data));
    const found = await repository.findOneBy({ id: saved.id } as Record<string, unknown>);
    expect(found).not.toBeNull();
    expect(found!.id).toBe(saved.id);
  });

  it('returns null for non-existent id', async () => {
    const found = await repository.findOneBy({
      id: '00000000-0000-0000-0000-000000000099',
    } as Record<string, unknown>);
    expect(found).toBeNull();
  });

  it('updates an entity field', async () => {
    const data = buildUserSession({ userId: userId });
    const saved = await repository.save(repository.create(data));
    saved.token = `updated-${Date.now()}`;
    const updated = await repository.save(saved);
    const reloaded = await repository.findOneBy({ id: saved.id } as Record<string, unknown>);
    expect(reloaded).not.toBeNull();
    expect(reloaded!.token).toEqual(updated.token);
  });

  it('deletes an entity', async () => {
    const data = buildUserSession({ userId: userId });
    const saved = await repository.save(repository.create(data));
    await repository.remove(saved);
    const found = await repository.findOneBy({ id: saved.id } as Record<string, unknown>);
    expect(found).toBeNull();
  });

  it('lists all entities', async () => {
    const data = buildUserSession({ userId: userId });
    await repository.save(repository.create(data));
    const all = await repository.find();
    expect(all.length).toBeGreaterThanOrEqual(1);
  });

  it('finds entity by unique field token', async () => {
    const data = buildUserSession({ userId: userId, token: `test-${Date.now()}` });
    const saved = await repository.save(repository.create(data));
    const found = await repository.findOneBy({
      token: `test-${Date.now()}`,
    } as Record<string, unknown>);
    expect(found).not.toBeNull();
    expect(found!.id).toBe(saved.id);
  });

  it('persists with userId foreign key', async () => {
    const data = buildUserSession({ userId: userId });
    const saved = await repository.save(repository.create(data));
    expect(saved.userId).toBe(userId);
  });
});
